import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Form, Button, Alert, Card } from 'react-bootstrap';
import '../Css/CreateProblem.css';

const CreateProblem = () => {
  const [activeTab, setActiveTab] = useState('problem'); // 'problem' or 'dailyChallenge'

  // Shared form data states for both tabs
  const [problemData, setProblemData] = useState({
    title: '',
    category: 'algebra',
    difficulty: 'easy',
    description: '',
    imageUrl: '',
    solution: ''
  });

  // Separate form data for daily challenge (customize fields as needed)
  const [dailyChallengeData, setDailyChallengeData] = useState({
    title: '',
    date: '',
    difficulty: 'easy',
    description: '',
    imageUrl: '',
    solution: ''
  });

  const [message, setMessage] = useState({ text: '', variant: '' });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e, type = 'problem') => {
    const value = e.target.value;
    const name = e.target.name;

    if (type === 'problem') {
      setProblemData(prev => ({ ...prev, [name]: value }));
    } else {
      setDailyChallengeData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e, type = 'problem') => {
    e.preventDefault();
    setLoading(true);
    setMessage({ text: '', variant: '' });

    const formData = type === 'problem' ? problemData : dailyChallengeData;
    const url =
      type === 'problem'
        ? 'http://localhost:5000/api/problems'
        : 'http://localhost:5000/api/dailychallenges'; // example endpoint

    try {
      const token = localStorage.getItem('token');
      const response = await axios.post(url, formData, {
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        timeout: 5000
      });

      setMessage({ text: `${type === 'problem' ? 'Problem' : 'Daily Challenge'} created successfully!`, variant: 'success' });

      // Reset form
      if (type === 'problem') {
        setProblemData({
          title: '',
          category: 'algebra',
          difficulty: 'easy',
          description: '',
          imageUrl: '',
          solution: ''
        });
      } else {
        setDailyChallengeData({
          title: '',
          date: '',
          difficulty: 'easy',
          description: '',
          imageUrl: '',
          solution: ''
        });
      }

      setTimeout(() => {
        navigate(type === 'problem' ? `/problems/${response.data._id}` : `/dailychallenges/${response.data._id}`);
      }, 2000);
    } catch (error) {
      setMessage({
        text: error.response?.data?.message || error.message || 'Network error - check console',
        variant: 'danger'
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="problem-list-page">
      <div className="problem-list-container">
        <Card className="create-problem-card">
          <h2>Create New Math Problem</h2>
          {/* Tabs */}
          <div className="tabs">
            <button
              className={`tab-button ${activeTab === 'problem' ? 'active' : ''}`}
              onClick={() => {
                setActiveTab('problem');
                setMessage({ text: '', variant: '' });
              }}
            >
              Create Problem
            </button>
            <button
              className={`tab-button ${activeTab === 'dailyChallenge' ? 'active' : ''}`}
              onClick={() => {
                setActiveTab('dailyChallenge');
                setMessage({ text: '', variant: '' });
              }}
            >
              Create Daily Challenge
            </button>
          </div>

          {message.text && (
            <Alert variant={message.variant} onClose={() => setMessage({ text: '', variant: '' })} dismissible>
              {message.text}
            </Alert>
          )}

          {activeTab === 'problem' && (
            <Form onSubmit={(e) => handleSubmit(e, 'problem')}>
              <Form.Group className="mb-3">
                <Form.Label className="form-label">Title</Form.Label>
                <Form.Control
                  type="text"
                  name="title"
                  value={problemData.title}
                  onChange={(e) => handleChange(e, 'problem')}
                  required
                  className="form-control"
                />
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Category</Form.Label>
                <Form.Select
                  name="category"
                  value={problemData.category}
                  onChange={(e) => handleChange(e, 'problem')}
                  required
                  className="form-select"
                >
                  <option value="algebra">Algebra</option>
                  <option value="geometry">Geometry</option>
                  <option value="calculus">Calculus</option>
                  <option value="trigonometry">Trigonometry</option>
                </Form.Select>
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Difficulty</Form.Label>
                <Form.Select
                  name="difficulty"
                  value={problemData.difficulty}
                  onChange={(e) => handleChange(e, 'problem')}
                  required
                  className="form-select"
                >
                  <option value="easy">Easy</option>
                  <option value="medium">Medium</option>
                  <option value="hard">Hard</option>
                </Form.Select>
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Description</Form.Label>
                <Form.Control
                  as="textarea"
                  name="description"
                  rows={5}
                  value={problemData.description}
                  onChange={(e) => handleChange(e, 'problem')}
                  required
                  className="form-control"
                />
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Image URL (optional)</Form.Label>
                <Form.Control
                  type="url"
                  name="imageUrl"
                  value={problemData.imageUrl}
                  onChange={(e) => handleChange(e, 'problem')}
                  placeholder="https://example.com/image.png"
                  className="form-control"
                />
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Solution</Form.Label>
                <Form.Control
                  as="textarea"
                  name="solution"
                  rows={4}
                  value={problemData.solution}
                  onChange={(e) => handleChange(e, 'problem')}
                  required
                  className="form-control"
                />
              </Form.Group>

              <Button type="submit" disabled={loading} className="submit-btn">
                {loading ? 'Creating...' : 'Create Problem'}
              </Button>
            </Form>
          )}

          {activeTab === 'dailyChallenge' && (
            <Form onSubmit={(e) => handleSubmit(e, 'dailyChallenge')}>
              <Form.Group className="mb-3">
                <Form.Label className="form-label">Title</Form.Label>
                <Form.Control
                  type="text"
                  name="title"
                  value={dailyChallengeData.title}
                  onChange={(e) => handleChange(e, 'dailyChallenge')}
                  required
                  className="form-control"
                />
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Date</Form.Label>
                <Form.Control
                  type="date"
                  name="date"
                  value={dailyChallengeData.date}
                  onChange={(e) => handleChange(e, 'dailyChallenge')}
                  required
                  className="form-control"
                />
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Difficulty</Form.Label>
                <Form.Select
                  name="difficulty"
                  value={dailyChallengeData.difficulty}
                  onChange={(e) => handleChange(e, 'dailyChallenge')}
                  required
                  className="form-select"
                >
                  <option value="easy">Easy</option>
                  <option value="medium">Medium</option>
                  <option value="hard">Hard</option>
                </Form.Select>
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Description</Form.Label>
                <Form.Control
                  as="textarea"
                  name="description"
                  rows={5}
                  value={dailyChallengeData.description}
                  onChange={(e) => handleChange(e, 'dailyChallenge')}
                  required
                  className="form-control"
                />
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Image URL (optional)</Form.Label>
                <Form.Control
                  type="url"
                  name="imageUrl"
                  value={dailyChallengeData.imageUrl}
                  onChange={(e) => handleChange(e, 'dailyChallenge')}
                  placeholder="https://example.com/image.png"
                  className="form-control"
                />
              </Form.Group>

              <Form.Group className="mb-3">
                <Form.Label className="form-label">Solution</Form.Label>
                <Form.Control
                  as="textarea"
                  name="solution"
                  rows={4}
                  value={dailyChallengeData.solution}
                  onChange={(e) => handleChange(e, 'dailyChallenge')}
                  required
                  className="form-control"
                />
              </Form.Group>

              <Button type="submit" disabled={loading} className="submit-btn">
                {loading ? 'Creating...' : 'Create Daily Challenge'}
              </Button>
            </Form>
          )}
        </Card>
      </div>

      {/* Inline minimal tab styles */}
      <style>{`

      `}</style>
    </div>
  );
};

export default CreateProblem;
